noncompliant:
#include <unistd.h>

void setup_jail() {
    // Noncompliant: using chroot without changing working directory
    chroot("/var/jail");
    // Process still has access outside jail
}

compliant:
#include <unistd.h>

void setup_jail() {
    // Compliant: change directory before chroot
    chdir("/var/jail");
    chroot("/var/jail");
    // Now properly isolated in jail
}
